import java.io.Serializable;

@SuppressWarnings("unchecked")
public class MockUtil {

    private final MockCreationValidator creationValidator;

    public MockUtil(MockCreationValidator creationValidator) {
        this.creationValidator = creationValidator;
    }

    public MockUtil() {
        this(new MockCreationValidator());
    }

    public <T> T createMock(Class<T> classToMock, MockSettingsImpl settings) {
        creationValidator.validateType(classToMock);
        creationValidator.validateExtraInterfaces(classToMock, settings.getExtraInterfaces());
        creationValidator.validateMockedType(classToMock, settings.getSpiedInstance());

        settings.initiateMockName(classToMock);

        MethodInterceptorFilter filter = newMethodInterceptorFilter(settings);
        Class<?>[] interfaces = settings.getExtraInterfaces();

        Class<?>[] ancillaryTypes;
        if (settings.isSerializable()) {
            ancillaryTypes = interfaces == null ? new Class<?>[] {Serializable.class} : new ArrayUtils().concat(interfaces, Serializable.class);
        } else {
            ancillaryTypes = interfaces == null ? new Class<?>[0] : interfaces;
        }

        Object spiedInstance = settings.getSpiedInstance();

        T mock = ClassImposterizer.INSTANCE.imposterise(filter, classToMock, ancillaryTypes);

        if (spiedInstance != null) {
            new LenientCopyTool().copyToMock(spiedInstance, mock);
        }

        return mock;
    }

    public <T> void resetMock(T mock) {
        MockHandlerInterface<T> oldMockHandler = getMockHandler(mock);
        MockSettingsImpl settings = (MockSettingsImpl) oldMockHandler.getMockSettings();

        // Check if the original mock had invocation listeners and thus used InvocationNotifierHandler
        if (settings.hasInvocationListeners()) {
            // Recreate the same structure with InvocationNotifierHandler
            MockHandler<T> newMockHandler = new MockHandler<T>(settings);
            MethodInterceptorFilter newFilter = new MethodInterceptorFilter(
                new InvocationNotifierHandler<T>(newMockHandler, settings),
                settings
            );
            ((Factory) mock).setCallback(0, newFilter);
        } else {
            // Original mock didn't have listeners, just use plain MockHandler
            MockHandler<T> newMockHandler = new MockHandler<T>(settings);
            MethodInterceptorFilter newFilter = new MethodInterceptorFilter(newMockHandler, settings);
            ((Factory) mock).setCallback(0, newFilter);
        }
    }

